    private static void buildTree(JSONObject node, int depth) {
        // Check depth constraint
        if (depth > 3) {
            return;
        }

        // Get team name
        String teamName = node.getString("teamName");
        List<Integer> members = new ArrayList<>();
        for (Object member : node.getJSONArray("members")) {
            members.add((Integer) member);
        }

        // Create node
        JSONObject teamNode = new JSONObject();
        teamNode.put("teamName", teamName);
        teamNode.put("members", members);

        // Add to tree
        if (depth == 0) {
            // Root node is "Organization"
            root.put("Organization", teamNode);
        } else {
            // Add to parent node
            JSONObject parent = (JSONObject) node.get(depth - 1);
            parent.put(teamName, teamNode);
        }

        // Recursively build children
        for (int i = 0; i < node.getJSONArray("members").length(); i++) {
            buildTree((JSONObject) node.getJSONArray("members").get(i), depth + 1);
        }
    }
}

