struct Employee {
    std::string name;
    std::vector<int> salaries;
};

class Tree {
public:
    Tree() : root(nullptr) {}

    ~Tree() {
        delete root;
    }

    Employee* createTree(const std::vector<std::pair<int, int>>& hierarchy) {
        // Initialize root
        root = new Employee();
        root->name = "Root";
        root->salaries = {1000};

        // Process hierarchy
        for (const auto& pair : hierarchy) {
            int manager = pair.first;
            int employee = pair.second;

            // Find manager and add employee as child
            Employee* managerNode = findNode(manager);
            if (managerNode) {
                // Add employee as child
                Employee* newEmployee = new Employee();
                newEmployee->name = "Employee " + std::to_string(employee);
                newEmployee->salaries = {2000};

                managerNode->salaries.push_back(newEmployee->salaries[0]);
                managerNode->children.push_back(newEmployee);
            }
        }

        // Ensure depth is at most 3
        if (depth(root) > 3) {
            // Remove nodes beyond depth 3
            std::vector<Employee*> toRemove;
            std::queue<Employee*> q;
            q.push(root);
            while (!q.empty()) {
                Employee* node = q.front();
                q.pop();
                if (depth(node) > 3) {
                    toRemove.push_back(node);
                }
                for (auto child : node->children) {
                    q.push(child);
                }
            }
            for (auto node : toRemove) {
                delete node;
            }
        }

        return root;
    }

private:
    Employee* root;
    std::vector<Employee*> children;
    int depth(Employee* node) {
        if (!node) return 0;
        return 1 + std::max(depth(node->children[0]), depth(node->children[1]));
    }

    Employee* findNode(int id) {
        if (!root) return nullptr;
        if (root->name == std::to_string(id)) return root;
        for (auto child : root->children) {
            if (findNode(id)) return child;
        }
        return nullptr;
    }
};

