        try (BufferedReader br = new BufferedReader(new FileReader("employees.json"))) {
            List<Employee> employees = new ArrayList<>();
            String line;
            while ((line = br.readLine()) != null) {
                employees.add(parseEmployee(line));
            }

            Map<Integer, Employee> employeeMap = employees.stream()
                    .collect(Collectors.toMap(Employee::getId, e -> e));

            // Build graph
            Set<Integer> nodeIds = new HashSet<>();
            for (Employee emp : employees) {
                nodeIds.add(emp.getId());
            }

            Map<Integer, List<Edge>> graph = new HashMap<>();
            for (int i = 0; i < nodeIds.size(); i++) {
                int nodeId = nodeIds.iterator().next();
                for (int j = 0; j < nodeIds.size(); j++) {
                    if (i == j) continue;
                    int otherNodeId = nodeIds.iterator().next();
                    if (otherNodeId == nodeId) continue;
                    int diff = Math.abs(employeeMap.get(nodeId).getSalary() - employeeMap.get(otherNodeId).getSalary());
                    if (diff < 5000) {
                        Edge edge = new Edge(nodeId, otherNodeId, diff);
                        if (!graph.containsKey(nodeId)) {
                            graph.put(nodeId, new ArrayList<>());
                        }
                        graph.get(nodeId).add(edge);
                    }
                }
            }

            // Output graph
            for (Map.Entry<Integer, List<Edge>> entry : graph.entrySet()) {
                int nodeId = entry.getKey();
                List<Edge> edges = entry.getValue();
                System.out.println("Node " + nodeId);
                for (Edge edge : edges) {
