fn construct_tree(nodes: Vec<(i32, i32)>) -> Option<Tree> {
    // Define the Tree struct
    #[derive(Debug, PartialEq, Eq)]
    struct Tree {
        id: i32,
        children: Vec<Tree>,
    }

    // Check if the input is empty
    if nodes.is_empty() {
        return None;
    }

    // Find the root node (id 0)
    let root = nodes.iter().find(|&&(id, _)| id == 0).unwrap();
    let (root_id, parent_id) = root;

    // Build the tree
    let mut tree = Tree {
        id: root_id,
        children: Vec::new(),
    };

    // Process each node
    for &(node_id, parent_id) in &nodes {
        // Check if the parent exists
        if let Some(parent) = tree.children.iter().find(|child| child.id == parent_id) {
            parent.children.push(Tree { id: node_id, children: Vec::new() });
        } else {
            return None; // Parent does not exist
        }
    }

    // Check depth constraint
    if tree.children.len() > 2 {
        return None; // Depth exceeds 3 levels
    }

    // Check child count constraint
    for child in &tree.children {
        if child.children.len() > 2 {
            return None; // Each node can have at most 2 children
        }
    }

    Some(tree)
}

